mapper.select:
SELECT pet_id, owner_id, pet_name, pet_type, default_req, image, profile_tags_json FROM pet_archives WHERE owner_id = #{ownerId}
AND pet_name LIKE CONCAT('%', #{petName}, '%')
AND pet_type = #{petType}
ORDER BY pet_id DESC

mapper.update:
UPDATE pet_archives
SET pet_name = #{petName},
    pet_type = #{petType},
    default_req = #{defaultReq},
    image = #{image},
    profile_tags_json = #{profileTagsJson}
WHERE pet_id = #{petId}
  AND owner_id = #{ownerId}

mapper.delete:
DELETE
FROM pet_archives
WHERE pet_id = #{petId}
  AND owner_id = #{ownerId}
